code.C:
#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t N; scanf("%lld", &N);
        int64_t ans = N*N - 3*N + 3; // N^2 - 3N + 3
        printf("%lld\n", ans);
    }
    return 0;
}

